# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import base64
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import functions_framework
import os
from datetime import datetime

PROJECT_ID = os.environ.get('GCP_PROJECT', 'your-project-id')
PUBSUB_TOPIC = os.environ.get('PUBSUB_TOPIC', 'file-processing-topic')
FIRESTORE_COLLECTION = os.environ.get('FIRESTORE_COLLECTION', 'processed_files')

storage_client = storage.Client()
db = firestore.Client()
publisher = pubsub_v1.PublisherClient()
topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

@functions_framework.cloud_event
def process_storage_file(cloud_event):
    data = cloud_event.data
    
    bucket_name = data['bucket']
    file_name = data['name']
    
    print(f"Processing file: gs://{bucket_name}/{file_name}")
    
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    file_content = blob.download_as_text()
    file_size = blob.size
    content_type = blob.content_type
    created_time = blob.time_created
    
    file_metadata = {
        'bucket': bucket_name,
        'file_name': file_name,
        'file_size': file_size,
        'content_type': content_type,
        'created_time': created_time,
        'processed_time': datetime.utcnow(),
        'content_preview': file_content[:500] if file_content else None
    }
    
    doc_ref = db.collection(FIRESTORE_COLLECTION).document()
    doc_ref.set(file_metadata)
    
    print(f"Written to Firestore with document ID: {doc_ref.id}")
    
    pubsub_message = {
        'document_id': doc_ref.id,
        'bucket': bucket_name,
        'file_name': file_name,
        'file_size': file_size,
        'event_type': 'file_processed'
    }
    
    message_json = json.dumps(pubsub_message)
    message_bytes = message_json.encode('utf-8')
    
    future = publisher.publish(topic_path, message_bytes)
    message_id = future.result()
    
    print(f"Published message to Pub/Sub with ID: {message_id}")
    
    return {
        'status': 'success',
        'document_id': doc_ref.id,
        'pubsub_message_id': message_id
    }

@functions_framework.http
def process_file_http(request):
    request_json = request.get_json(silent=True)
    
    if not request_json or 'bucket' not in request_json or 'file_name' not in request_json:
        return {'error': 'Missing bucket or file_name in request'}, 400
    
    bucket_name = request_json['bucket']
    file_name = request_json['file_name']
    
    try:
        bucket = storage_client.bucket(bucket_name)
        blob = bucket.blob(file_name)
        
        if not blob.exists():
            return {'error': f'File not found: gs://{bucket_name}/{file_name}'}, 404
        
        file_content = blob.download_as_text()
        file_size = blob.size
        content_type = blob.content_type
        created_time = blob.time_created
        
        file_metadata = {
            'bucket': bucket_name,
            'file_name': file_name,
            'file_size': file_size,
            'content_type': content_type,
            'created_time': created_time,
            'processed_time': datetime.utcnow(),
            'content_preview': file_content[:500] if file_content else None
        }
        
        doc_ref = db.collection(FIRESTORE_COLLECTION).document()
        doc_ref.set(file_metadata)
        
        pubsub_message = {
            'document_id': doc_ref.id,
            'bucket': bucket_name,
            'file_name': file_name,
            'file_size': file_size,
            'event_type': 'file_processed'
        }
        
        message_json = json.dumps(pubsub_message)
        message_bytes = message_json.encode('utf-8')
        
        future = publisher.publish(topic_path, message_bytes)
        message_id = future.result()
        
        return {
            'status': 'success',
            'document_id': doc_ref.id,
            'pubsub_message_id': message_id,
            'file_size': file_size
        }, 200
        
    except Exception as e:
        print(f"Error processing file: {str(e)}")
        return {'error': str(e)}, 500

@functions_framework.cloud_event
def process_pubsub_message(cloud_event):
    pubsub_message = base64.b64decode(cloud_event.data['message']['data']).decode()
    
    print(f"Received Pub/Sub message: {pubsub_message}")
    
    message_data = json.loads(pubsub_message)
    
    processing_result = {
        'original_message': message_data,
        'processed_at': datetime.utcnow(),
        'status': 'completed'
    }
    
    doc_ref = db.collection('pubsub_messages').document()
    doc_ref.set(processing_result)
    
    print(f"Stored Pub/Sub message in Firestore: {doc_ref.id}")
    
    return {'status': 'success', 'document_id': doc_ref.id}

def batch_process_files(bucket_name, prefix=''):
    bucket = storage_client.bucket(bucket_name)
    blobs = bucket.list_blobs(prefix=prefix)
    
    processed_files = []
    
    for blob in blobs:
        try:
            file_metadata = {
                'bucket': bucket_name,
                'file_name': blob.name,
                'file_size': blob.size,
                'content_type': blob.content_type,
                'created_time': blob.time_created,
                'processed_time': datetime.utcnow()
            }
            
            doc_ref = db.collection(FIRESTORE_COLLECTION).document()
            doc_ref.set(file_metadata)
            
            pubsub_message = {
                'document_id': doc_ref.id,
                'bucket': bucket_name,
                'file_name': blob.name,
                'file_size': blob.size,
                'event_type': 'batch_processed'
            }
            
            message_json = json.dumps(pubsub_message)
            message_bytes = message_json.encode('utf-8')
            
            future = publisher.publish(topic_path, message_bytes)
            message_id = future.result()
            
            processed_files.append({
                'file_name': blob.name,
                'document_id': doc_ref.id,
                'message_id': message_id
            })
            
        except Exception as e:
            print(f"Error processing {blob.name}: {str(e)}")
    
    return processed_files